def calculate_consensus(all_american_lists):
    # Initialize a dictionary to keep track of player points
    player_points = {}

    # Define point values for each team level
    points = {
        'first_team': 3,
        'second_team': 2,
        'third_team': 1
    }

    # Iterate through each selector's list
    for selector, teams in all_american_lists.items():
        for team_type, players in teams.items():
            if team_type in points:
                for player in players:
                    player_points[player] = player_points.get(player, 0) + points[team_type]

    # Sort players by points in descending order
    sorted_players = sorted(player_points.items(), key=lambda x: -x[1])

    # Determine first and second teams
    consensus_first_team = [player for player, points in sorted_players[:5]]
    consensus_second_team = [player for player, points in sorted_players[5:10]]

    return {
        'first_team': consensus_first_team,
        'second_team': consensus_second_team
    }

# Example usage:
all_american_lists = {
    'AP': {
        'first_team': ['PlayerA', 'PlayerB', 'PlayerC'],
        'second_team': ['PlayerD', 'PlayerE'],
        'third_team': ['PlayerF']
    },
    'USBWA': {
        'first_team': ['PlayerA', 'PlayerB', 'PlayerD'],
        'second_team': ['PlayerC', 'PlayerE'],
        'third_team': ['PlayerG']
    }
    # Additional selectors would be included here
}

consensus_team = calculate_consensus(all_american_lists)
print(consensus_team)
This function takes a dictionary of All-American lists from different selectors and calculates the consensus first and second teams based on the point system.
